#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define INF 1000000

void floydWarshall(int* dist, int n) {
    for (int k = 0; k < n; k++) {
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; i++) {
            int i_n = i * n;
            for (int j = 0; j < n; j++) {
                int ij = i_n + j;
                int ik = i_n + k;
                int kj = k * n + j;
                if (dist[ik] + dist[kj] < dist[ij]) {
                    dist[ij] = dist[ik] + dist[kj];
                }
            }
        }
    }
}

int main(int argc, char** argv) {
    if (argc != 2) {
        printf("Usage: %s <matrix_size>\n", argv[0]);
        return 1;
    }
    int n = atoi(argv[1]);
    int* dist = (int*)malloc(n * n * sizeof(int));
    if (!dist) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Initialize the distance matrix
    for (int i = 0; i < n; i++) {
        int i_n = i * n;
        for (int j = 0; j < n; j++) {
            if (i == j)
                dist[i_n + j] = 0;
            else
                dist[i_n + j] = (rand() % 20) + 1;
        }
    }

    floydWarshall(dist, n);

    // Print the resulting distance matrix
    for (int i = 0; i < n; i++) {
        int i_n = i * n;
        for (int j = 0; j < n; j++) {
            if (dist[i_n + j] >= INF)
                printf("INF ");
            else
                printf("%d ", dist[i_n + j]);
        }
        printf("\n");
    }

    free(dist);
    return 0;
}
